/**
 * AssignmentsPanel.jsx
 *
 * Assign a zoom settings rule to specific WooCommerce product categories
 * and/or individual products.
 *
 * Architecture (mirrors FormSettingsPanel.jsx from the form builder):
 *  - No local Save button. PluginSettingsApp calls assignmentsSaveRef.current(id)
 *    inside handleSave, so assignments save atomically with the settings row.
 *  - assignmentsSaveRef.current receives the final id at call time — safe for
 *    new items that didn't have an id when the panel mounted.
 *  - Category tree shows a flat filtered list when the filter input is active.
 *  - Product search is debounced at 350 ms.
 */

import { __, _n, sprintf } from "@wordpress/i18n";
import {
    useState,
    useEffect,
    useCallback,
    useRef,
    useMemo,
    createPortal,
} from "@wordpress/element";
import {
    Check,
    Search,
    X,
    Loader2,
    ChevronDown,
    ChevronRight,
    Tag,
    Package,
    AlertTriangle,
} from "lucide-react";
import {
    getAssignments,
    saveAssignments,
    getWcCategories,
    searchWcProducts,
    getWcProductsByIds,
} from "../../api/assignments";
import { ButtonGroup } from "../ui/index";

const APPLY_TO_OPTIONS = [
    { value: "all", label: __("All Products", "wpbean-product-gallery-slider-for-woocommerce") },
    { value: "selected", label: __("Selected Only", "wpbean-product-gallery-slider-for-woocommerce") },
];

// ── Helpers ───────────────────────────────────────────────────────────────────

const buildTree = (cats, parent = 0) =>
    cats
        .filter((c) => c.parent === parent)
        .map((c) => ({ ...c, children: buildTree(cats, c.id) }));

// ── Category tree node ────────────────────────────────────────────────────────

const CategoryNode = ({ node, selected, onToggle, depth = 0 }) => {
    const [expanded, setExpanded] = useState(depth < 1);
    const isSelected = selected.includes(node.id);
    const hasChildren = node.children?.length > 0;

    return (
        <div>
            <div
                className={[
                    "flex items-center gap-1.5 rounded-md py-[6px] cursor-pointer",
                    "transition-colors duration-100",
                    isSelected ? "bg-blue-50" : "hover:bg-gray-50",
                ].join(" ")}
                style={{
                    paddingLeft: `${10 + depth * 14}px`,
                    paddingRight: "10px",
                }}
                onClick={() => onToggle(node.id)}
            >
                {/* Expand/collapse chevron */}
                {hasChildren ? (
                    <button
                        className="h-4 w-4 shrink-0 flex items-center justify-center rounded text-gray-300 hover:text-gray-500 transition-colors"
                        onClick={(e) => {
                            e.stopPropagation();
                            setExpanded((v) => !v);
                        }}
                        aria-label={expanded ? __("Collapse", "wpbean-product-gallery-slider-for-woocommerce") : __("Expand", "wpbean-product-gallery-slider-for-woocommerce")}
                    >
                        {expanded ? (
                            <ChevronDown size={11} />
                        ) : (
                            <ChevronRight size={11} />
                        )}
                    </button>
                ) : (
                    <span className="w-4 shrink-0" />
                )}

                {/* Checkbox */}
                <span
                    className={[
                        "h-[15px] w-[15px] shrink-0 rounded-[3px] border-[1.5px]",
                        "flex items-center justify-center transition-colors duration-100",
                        isSelected
                            ? "border-blue-600 bg-blue-600"
                            : "border-gray-200 bg-white",
                    ].join(" ")}
                >
                    {isSelected && (
                        <Check
                            size={9}
                            strokeWidth={3}
                            className="text-white"
                        />
                    )}
                </span>

                {/* Label */}
                <span
                    className={[
                        "flex-1 min-w-0 truncate text-[12px] leading-none transition-colors duration-100",
                        isSelected
                            ? "font-medium text-blue-600"
                            : "text-gray-600",
                    ].join(" ")}
                >
                    {node.name}
                </span>

                {/* Count */}
                {node.count > 0 && (
                    <span className="shrink-0 tabular-nums text-[10px] text-gray-300">
                        {node.count}
                    </span>
                )}
            </div>

            {hasChildren && expanded && (
                <div>
                    {node.children.map((child) => (
                        <CategoryNode
                            key={child.id}
                            node={child}
                            selected={selected}
                            onToggle={onToggle}
                            depth={depth + 1}
                        />
                    ))}
                </div>
            )}
        </div>
    );
};

// ── Flat filtered category row ────────────────────────────────────────────────

const CategoryFlatRow = ({ cat, selected, onToggle }) => {
    const isSelected = selected.includes(cat.id);
    return (
        <div
            className={[
                "flex items-center gap-1.5 rounded-md px-2.5 py-[6px] cursor-pointer",
                "transition-colors duration-100",
                isSelected ? "bg-blue-50" : "hover:bg-gray-50",
            ].join(" ")}
            onClick={() => onToggle(cat.id)}
        >
            <span
                className={[
                    "h-[15px] w-[15px] shrink-0 rounded-[3px] border-[1.5px]",
                    "flex items-center justify-center transition-colors duration-100",
                    isSelected
                        ? "border-blue-600 bg-blue-600"
                        : "border-gray-200 bg-white",
                ].join(" ")}
            >
                {isSelected && (
                    <Check size={9} strokeWidth={3} className="text-white" />
                )}
            </span>
            <span
                className={[
                    "flex-1 min-w-0 truncate text-[12px]",
                    isSelected ? "font-medium text-blue-600" : "text-gray-600",
                ].join(" ")}
            >
                {cat.name}
            </span>
            {cat.count > 0 && (
                <span className="shrink-0 tabular-nums text-[10px] text-gray-300">
                    {cat.count}
                </span>
            )}
        </div>
    );
};

// ── Accordion header ──────────────────────────────────────────────────────────

