// ── Categories section ────────────────────────────────────────────────────────

const CategoriesSection = ({
    categories,
    selected,
    onToggle,
    isOpen,
    onOpenToggle,
}) => {
    const [filterQuery, setFilterQuery] = useState("");

    const tree = useMemo(() => buildTree(categories), [categories]);

    const filtered = useMemo(() => {
        if (!filterQuery.trim()) return null;
        const q = filterQuery.toLowerCase();
        return categories.filter((c) => c.name.toLowerCase().includes(q));
    }, [filterQuery, categories]);

    const isFiltering = filtered !== null;

    return (
        <div className="border-b border-gray-100">
            <AccordionHeader
                icon={Tag}
                label={__("Product Categories", "wpbean-product-gallery-slider-for-woocommerce")}
                count={selected.length}
                isOpen={isOpen}
                onToggle={onOpenToggle}
            />

            {isOpen && (
                <div className="px-4 pb-4">
                    <p className="mb-3 px-0.5 text-[11.5px] leading-relaxed text-gray-400">
                        {__("Apply this rule to all products in the selected categories.", "wpbean-product-gallery-slider-for-woocommerce")}
                    </p>

                    {categories.length === 0 ? (
                        <p className="text-[12px] text-gray-400 px-1 py-1">
                            {__("No WooCommerce categories found.", "wpbean-product-gallery-slider-for-woocommerce")}
                        </p>
                    ) : (
                        <>
                            {/* Filter — only when list is large enough */}
                            {categories.length > 6 && (
                                <div className="relative mb-2.5">
                                    <Search
                                        size={11}
                                        className="absolute start-2.5 top-1/2 -translate-y-1/2 text-gray-300 pointer-events-none"
                                    />
                                    <input
                                        type="text"
                                        className={[
                                            "w-full rounded-lg border border-gray-200 bg-gray-50 py-[7px] ps-7 pe-7",
                                            "text-[12px] text-gray-800 placeholder:text-gray-400 outline-none",
                                            "transition-colors duration-150 focus:border-blue-400 focus:bg-white focus:ring-1 focus:ring-blue-500/20",
                                        ].join(" ")}
                                        placeholder={__("Filter categories…", "wpbean-product-gallery-slider-for-woocommerce")}
                                        value={filterQuery}
                                        onChange={(e) =>
                                            setFilterQuery(e.target.value)
                                        }
                                    />
                                    {filterQuery && (
                                        <button
                                            className="absolute end-2.5 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-500"
                                            onClick={() => setFilterQuery("")}
                                        >
                                            <X size={11} />
                                        </button>
                                    )}
                                </div>
                            )}

                            <div className="max-h-[220px] overflow-y-auto rounded-lg border border-gray-100 fb-scrollbar-thin">
                                {isFiltering ? (
                                    filtered.length === 0 ? (
                                        <p className="px-3 py-3 text-[12px] text-gray-400">
                                            {sprintf(__('No categories match "%s"', "wpbean-product-gallery-slider-for-woocommerce"), filterQuery)}
                                        </p>
                                    ) : (
                                        <div className="p-1">
                                            {filtered.map((cat) => (
                                                <CategoryFlatRow
                                                    key={cat.id}
                                                    cat={cat}
                                                    selected={selected}
                                                    onToggle={onToggle}
                                                />
                                            ))}
                                        </div>
                                    )
                                ) : (
                                    <div className="p-1">
                                        {tree.map((node) => (
                                            <CategoryNode
                                                key={node.id}
                                                node={node}
                                                selected={selected}
                                                onToggle={onToggle}
                                            />
                                        ))}
                                    </div>
                                )}
                            </div>

                            {selected.length > 0 && (
                                <p className="mt-2 px-0.5 text-[11px] font-medium text-blue-600">
                                    {sprintf(
                                        _n("%d category selected", "%d categories selected", selected.length, "wpbean-product-gallery-slider-for-woocommerce"),
                                        selected.length,
                                    )}
                                </p>
                            )}
                        </>
                    )}
                </div>
            )}
        </div>
    );
};

// ── Product search ────────────────────────────────────────────────────────────

const ProductSearch = ({ selectedProducts, onAdd }) => {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState([]);
    const [loading, setLoading] = useState(false);
    const [open, setOpen] = useState(false);
    const [dropdownPos, setDropdownPos] = useState({
        top: 0,
        left: 0,
        width: 0,
    });
    const timerRef = useRef(null);
    const wrapRef = useRef(null);
    const dropdownRef = useRef(null);

    // Compute portal position from the wrapper's bounding rect.
    // Runs on open and on any scroll / resize so it stays aligned.
    const updatePos = useCallback(() => {
        if (!wrapRef.current) return;
        const r = wrapRef.current.getBoundingClientRect();
        setDropdownPos({ top: r.bottom + 4, left: r.left, width: r.width });
    }, []);

    useEffect(() => {
        if (!open) return;
        updatePos();
        window.addEventListener("scroll", updatePos, {
            capture: true,
            passive: true,
        });
        window.addEventListener("resize", updatePos, { passive: true });
        return () => {
            window.removeEventListener("scroll", updatePos, { capture: true });
            window.removeEventListener("resize", updatePos);
        };
    }, [open, updatePos]);

    // Close on outside click — must check both the input wrapper AND the portal
    // dropdown (which lives in document.body, outside wrapRef).
    useEffect(() => {
        if (!open) return;
        const handler = (e) => {
            const inInput = wrapRef.current?.contains(e.target);
            const inDropdown = dropdownRef.current?.contains(e.target);
            if (!inInput && !inDropdown) setOpen(false);
        };
        document.addEventListener("mousedown", handler);
        return () => document.removeEventListener("mousedown", handler);
    }, [open]);

    // Debounced search
    useEffect(() => {
        if (!query.trim()) {
            setResults([]);
            setOpen(false);
            return;
        }
        clearTimeout(timerRef.current);
        timerRef.current = setTimeout(async () => {
            setLoading(true);
            try {
                const data = await searchWcProducts({
                    search: query,
                    per_page: 15,
                });
                setResults(data.items ?? []);
                setOpen(true);
                updatePos();
            } catch {
                setResults([]);
            } finally {
                setLoading(false);
            }
        }, 350);
        return () => clearTimeout(timerRef.current);
    }, [query]);

    const handleSelect = (product) => {
        if (!selectedProducts.find((p) => p.id === product.id)) onAdd(product);
        setQuery("");
        setResults([]);
        setOpen(false);
    };

    // Portal dropdown — rendered at body level so no overflow clipping occurs.
    // Outer div carries `wpbean-pgs-wrapper` so PostCSS-scoped Tailwind classes apply.
    const dropdown =
        open &&
        createPortal(
            <div
                className="wpbean-pgs-wrapper"
                style={{
                    position: "fixed",
                    top: dropdownPos.top,
                    left: dropdownPos.left,
                    width: dropdownPos.width,
                    zIndex: 999999,
                }}
            >
                <div
                    ref={dropdownRef}
                    className="overflow-hidden rounded-xl border border-gray-100 bg-white shadow-[0_8px_32px_rgba(0,0,0,0.12)]"
                >
                    {results.length > 0 ? (
                        <div className="max-h-[256px] overflow-y-auto fb-scrollbar-thin divide-y divide-gray-50">
                            {results.map((product) => {
                                const added = !!selectedProducts.find(
                                    (p) => p.id === product.id,
                                );
                                return (
                                    <button
                                        key={product.id}
                                        className={[
                                            "flex w-full items-center gap-3 px-3 py-2.5 text-start transition-colors duration-100",
                                            added
                                                ? "cursor-default bg-gray-50/60"
                                                : "hover:bg-blue-50/50",
                                        ].join(" ")}
                                        onClick={() =>
                                            !added && handleSelect(product)
                                        }
                                        disabled={added}
                                    >
                                        {/* Thumbnail */}
                                        <div className="h-9 w-9 shrink-0 rounded-lg overflow-hidden border border-gray-100 bg-gray-50 flex items-center justify-center">
                                            {product.image ? (
                                                <img
                                                    src={product.image}
                                                    alt=""
                                                    style={{
                                                        width: "100%",
                                                        height: "100%",
                                                        objectFit: "cover",
                                                    }}
                                                />
                                            ) : (
                                                <Package
                                                    size={14}
                                                    className="text-gray-300"
                                                />
                                            )}
                                        </div>

                                        {/* Name + meta */}
                                        <div className="flex min-w-0 flex-1 flex-col gap-[3px]">
                                            <span
                                                className={[
                                                    "truncate text-[12.5px] font-medium leading-tight",
                                                    added
                                                        ? "text-gray-400"
                                                        : "text-gray-800",
                                                ].join(" ")}
                                            >
                                                {product.name}
                                            </span>
                                            <span className="flex items-center gap-1.5 text-[10.5px] leading-none text-gray-400">
                                                <span className="rounded bg-gray-100 px-1 py-px font-mono text-[9.5px] text-gray-500">
                                                    #{product.id}
                                                </span>
                                                {product.sku && (
                                                    <span className="text-gray-300">
                                                        SKU: {product.sku}
                                                    </span>
                                                )}
                                            </span>
                                        </div>

                                        {/* Added check */}
                                        {added ? (
                                            <Check
                                                size={13}
                                                className="shrink-0 text-blue-400"
                                            />
                                        ) : (
                                            <span className="shrink-0 rounded-md border border-blue-100 bg-blue-50 px-2 py-0.5 text-[10px] font-medium text-blue-500 opacity-0 transition-opacity duration-100 group-hover:opacity-100">
                                                Add
                                            </span>
                                        )}
                                    </button>
                                );
                            })}
                        </div>
                    ) : loading ? (
                        <div className="flex items-center justify-center gap-2 px-4 py-5 text-[12px] text-gray-400">
                            <Loader2 size={13} className="animate-spin" />
                            {__("Searching…", "wpbean-product-gallery-slider-for-woocommerce")}
                        </div>
                    ) : (
                        query.trim() && (
                            <div className="px-4 py-5 text-center">
                                <p className="text-[12px] font-medium text-gray-500">
                                    {__("No products found", "wpbean-product-gallery-slider-for-woocommerce")}
                                </p>
                                <p className="mt-0.5 text-[11px] text-gray-400">
                                    {__("Try a different name or SKU", "wpbean-product-gallery-slider-for-woocommerce")}
                                </p>
                            </div>
                        )
                    )}
                </div>
            </div>,
            document.body,
        );

    return (
        <div ref={wrapRef} className="relative">
            <div className="relative flex items-center">
                {loading ? (
                    <Loader2
                        size={12}
                        className="absolute start-3 top-1/2 -translate-y-1/2 text-gray-300 animate-spin pointer-events-none"
                    />
                ) : (
                    <Search
                        size={12}
                        className="absolute start-3 top-1/2 -translate-y-1/2 text-gray-300 pointer-events-none"
                    />
                )}
                <input
                    type="text"
                    className={[
                        "w-full rounded-xl border border-gray-200 bg-gray-50 py-2.5 ps-8 pe-3",
                        "text-[12.5px] text-gray-800 placeholder:text-gray-400 outline-none",
                        "transition-all duration-150 focus:border-blue-400 focus:bg-white focus:ring-2 focus:ring-blue-500/10",
                    ].join(" ")}
                    placeholder={__("Search products by name or SKU…", "wpbean-product-gallery-slider-for-woocommerce")}
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onFocus={() =>
                        results.length > 0 && (updatePos(), setOpen(true))
                    }
                />
                {query && (
                    <button
                        className="absolute end-2.5 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-500"
                        onClick={() => {
                            setQuery("");
                            setResults([]);
                            setOpen(false);
                        }}
                    >
                        <X size={12} />
                    </button>
                )}
            </div>
            {dropdown}
        </div>
    );
};

