// ── Main panel ────────────────────────────────────────────────────────────────

const AssignmentsPanel = ({
    id,
    assignmentsSaveRef,
    onAssignmentsDirty,
    onAssignmentsClean,
}) => {
    const isNew = !id || id === 0;

    const [applyTo, setApplyTo] = useState("all");
    const [categories, setCategories] = useState([]);
    const [selectedCategories, setSelectedCategories] = useState([]);
    const [selectedProducts, setSelectedProducts] = useState([]);
    const [loadingInit, setLoadingInit] = useState(true);
    const [catOpen, setCatOpen] = useState(true);
    const [prodOpen, setProdOpen] = useState(false);

    const savedSnapshotRef = useRef(null);

    // ── Snapshot helpers ──────────────────────────────────────────────────────

    const getCurrentSnapshot = useCallback(
        () =>
            JSON.stringify({
                applyTo,
                categories: [...selectedCategories].sort(),
                products: selectedProducts.map((p) => p.id).sort(),
            }),
        [applyTo, selectedCategories, selectedProducts],
    );

    // Notify parent whenever assignments dirty state changes.
    useEffect(() => {
        if (!savedSnapshotRef.current) return; // still loading — don't fire yet
        const dirty = savedSnapshotRef.current !== getCurrentSnapshot();
        if (dirty) {
            onAssignmentsDirty?.();
        } else {
            onAssignmentsClean?.();
        }
    }, [
        applyTo,
        selectedCategories,
        selectedProducts,
        getCurrentSnapshot,
        onAssignmentsDirty,
        onAssignmentsClean,
    ]);

    // ── Load ──────────────────────────────────────────────────────────────────

    useEffect(() => {
        let cancelled = false;

        (async () => {
            try {
                // Always load the category tree — even for new items.
                // Only fetch existing assignments when the row already exists.
                const [cats, assignments] = await Promise.all([
                    getWcCategories(),
                    isNew
                        ? Promise.resolve({
                              apply_to: "all",
                              categories: [],
                              products: [],
                          })
                        : getAssignments(id),
                ]);
                if (cancelled) return;

                setCategories(cats);
                setApplyTo(assignments.apply_to ?? "all");
                setSelectedCategories(assignments.categories ?? []);

                if (!isNew && assignments.products?.length) {
                    const data = await getWcProductsByIds(
                        assignments.products,
                    ).catch(() => ({ items: [] }));

                    const itemMap = Object.fromEntries(
                        (data.items ?? []).map((p) => [p.id, p]),
                    );
                    const resolved = assignments.products.map(
                        (pid) =>
                            itemMap[pid] ?? {
                                id: pid,
                                name: `Product #${pid}`,
                                sku: "",
                            },
                    );

                    if (!cancelled) setSelectedProducts(resolved);
                }

                if (!cancelled) {
                    savedSnapshotRef.current = JSON.stringify({
                        applyTo: assignments.apply_to ?? "all",
                        categories: [...(assignments.categories ?? [])].sort(),
                        products: [...(assignments.products ?? [])].sort(),
                    });
                    onAssignmentsClean?.(); // start clean after load
                }
            } catch {
                /* panel renders empty */
            } finally {
                if (!cancelled) setLoadingInit(false);
            }
        })();

        return () => {
            cancelled = true;
        };
    }, [id]);

    // ── Expose save — called by PluginSettingsApp.handleSave ─────────────────

    useEffect(() => {
        if (!assignmentsSaveRef) return;
        assignmentsSaveRef.current = async (finalId) => {
            if (!finalId || finalId === 0) return;
            await saveAssignments(
                finalId,
                applyTo,
                selectedCategories,
                selectedProducts.map((p) => p.id),
            );
            savedSnapshotRef.current = JSON.stringify({
                applyTo,
                categories: [...selectedCategories].sort(),
                products: selectedProducts.map((p) => p.id).sort(),
            });
            onAssignmentsClean?.(); // reset dirty after save
        };
    }, [
        applyTo,
        selectedCategories,
        selectedProducts,
        assignmentsSaveRef,
        onAssignmentsClean,
    ]);

    // ── Handlers ──────────────────────────────────────────────────────────────

    const toggleCategory = useCallback(
        (termId) =>
            setSelectedCategories((prev) =>
                prev.includes(termId)
                    ? prev.filter((c) => c !== termId)
                    : [...prev, termId],
            ),
        [],
    );

    const addProduct = useCallback(
        (p) => setSelectedProducts((prev) => [...prev, p]),
        [],
    );
    const removeProduct = useCallback(
        (pid) =>
            setSelectedProducts((prev) => prev.filter((p) => p.id !== pid)),
        [],
    );

    // ── Loading ───────────────────────────────────────────────────────────────

    if (loadingInit) {
        return (
            <div className="flex h-40 items-center justify-center gap-2 text-[12px] text-gray-300">
                <Loader2 size={16} className="animate-spin" />
                {__("Loading assignments…", "wpbean-product-gallery-slider-for-woocommerce")}
            </div>
        );
    }

    const showPickers = applyTo === "selected";
    const totalSelected = selectedCategories.length + selectedProducts.length;

    return (
        <div className="mx-auto max-w-[680px] pb-10 space-y-4">
            {/* ── Apply to selector ── */}
            <div className="overflow-hidden rounded-xl border border-gray-200 bg-white">
                <div className="border-b border-gray-100 bg-gray-50/60 px-5 py-[14px]">
                    <h3 className="text-[13px] font-semibold text-gray-700">
                        {__("Apply Rule To", "wpbean-product-gallery-slider-for-woocommerce")}
                    </h3>
                    <p className="mt-0.5 text-[11.5px] leading-relaxed text-gray-400">
                        {__("Choose whether this zoom rule applies to all products or only specific ones.", "wpbean-product-gallery-slider-for-woocommerce")}
                    </p>
                </div>
                <div className="px-5 py-4">
                    <ButtonGroup
                        options={APPLY_TO_OPTIONS}
                        value={applyTo}
                        onChange={setApplyTo}
                    />
                    {applyTo === "all" && (
                        <p className="mt-3 text-[11.5px] text-gray-400 leading-relaxed">
                            This rule will be applied to{" "}
                            <span className="font-medium text-gray-600">
                                {__("all products", "wpbean-product-gallery-slider-for-woocommerce")}
                            </span>{" "}
                            {__('in your store. To limit it, switch to "Selected Only".', "wpbean-product-gallery-slider-for-woocommerce")}
                        </p>
                    )}
                </div>
            </div>

            {/* ── Category & product pickers (conditional) ── */}
            {showPickers && (
                <div className="overflow-hidden rounded-xl border border-gray-200 bg-white">
                    <CategoriesSection
                        categories={categories}
                        selected={selectedCategories}
                        onToggle={toggleCategory}
                        isOpen={catOpen}
                        onOpenToggle={() => setCatOpen((v) => !v)}
                    />

                    <ProductsSection
                        selectedProducts={selectedProducts}
                        onAdd={addProduct}
                        onRemove={removeProduct}
                        isOpen={prodOpen}
                        onOpenToggle={() => setProdOpen((v) => !v)}
                    />

                    {totalSelected > 0 && (
                        <div className="m-4 flex items-start gap-2.5 rounded-lg border border-amber-200 bg-amber-50 px-4 py-3">
                            <AlertTriangle
                                size={14}
                                className="mt-px shrink-0 text-amber-500"
                            />
                            <p className="text-[11.5px] leading-relaxed text-amber-700">
                                {__("If a product matches multiple rules, the rule with the highest ID (most recently created) will be applied.", "wpbean-product-gallery-slider-for-woocommerce")}
                            </p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default AssignmentsPanel;
