// ── Root panel — routes to the active sub-panel ───────────────────────────────

export default function GalleryPanel() {
    const {
        state: { settings, gallerySubTab },
        actions,
    } = useSettings();
    const s = (key, val) => actions.set(key, val);

    switch (gallerySubTab) {
        case "general":
            return (
                <GeneralSubPanel
                    settings={settings}
                    s={s}
                    actions={actions}
                    gallerySubTab={gallerySubTab}
                />
            );
        case "main-image":
            return <MainImageSubPanel settings={settings} s={s} />;
        case "navigation":
            return (
                <NavigationSubPanel
                    settings={settings}
                    actions={actions}
                    s={s}
                />
            );
        case "transition":
            if (
                settings.galleryType === "anchor" ||
                settings.galleryType === "sticky-split" ||
                settings.galleryType === "hierarchy-grid" ||
                settings.galleryType === "tiles"
            ) {
                return (
                    <GeneralSubPanel
                        settings={settings}
                        s={s}
                        actions={actions}
                        gallerySubTab={gallerySubTab}
                    />
                );
            }
            return <TransitionSubPanel settings={settings} s={s} />;
        case "stacked":
            return (
                <StackedSubPanel settings={settings} s={s} actions={actions} />
            );
        case "sticky-split":
            return <StickySplitSubPanel settings={settings} s={s} />;
        case "hierarchy-grid":
            return <HierarchyGridSubPanel settings={settings} s={s} />;
        case "tiles":
            return <TilesSubPanel settings={settings} s={s} />;
        default:
            return <ThumbnailsSubPanel settings={settings} s={s} />;
    }
}
